func splitPath(path string) []string {
	trimmed := strings.Trim(strings.TrimSpace(path), "/")
	if trimmed == "" {
		return nil
	}
	return strings.Split(trimmed, "/")
}

func matchPath(pattern string, actual string) (map[string]string, bool) {
	patternParts := splitPath(normalizePath(pattern))
	actualParts := splitPath(normalizePath(actual))
	params := map[string]string{}

	for index := 0; index < len(patternParts); index++ {
		if index >= len(actualParts) {
			if strings.HasPrefix(patternParts[index], "*") {
				params[strings.TrimPrefix(patternParts[index], "*")] = ""
				return params, true
			}
			return nil, false
		}

		part := patternParts[index]
		if strings.HasPrefix(part, ":") {
			params[strings.TrimPrefix(part, ":")] = actualParts[index]
			continue
		}

		if strings.HasPrefix(part, "*") {
			params[strings.TrimPrefix(part, "*")] = strings.Join(actualParts[index:], "/")
			return params, true
		}

		if part != actualParts[index] {
			return nil, false
		}
	}

	if len(actualParts) != len(patternParts) {
		return nil, false
	}

	return params, true
}

func decodeBody(body *compatibilityBody) ([]byte, error) {
	if body == nil || body.Value == "" {
		return nil, nil
	}
	if body.Encoding != "base64" {
		return nil, fmt.Errorf("unsupported body encoding %q", body.Encoding)
	}
	return base64.StdEncoding.DecodeString(body.Value)
}

func encodeBody(body []byte) *compatibilityBody {
	if len(body) == 0 {
		return nil
	}
	return &compatibilityBody{
		Encoding: "base64",
		Value:    base64.StdEncoding.EncodeToString(body),
	}
}

func flattenHeaders(headers http.Header) map[string]string {
	flattened := make(map[string]string, len(headers))
	for key, values := range headers {
		flattened[key] = strings.Join(values, ", ")
	}
	return flattened
}

func (engine *Engine) dispatch(request XGnosisCompatibilityRequest) (XGnosisCompatibilityResponse, error) {
	if strings.ToLower(request.Framework) != "gin" {
		return XGnosisCompatibilityResponse{}, fmt.Errorf("unsupported framework %q", request.Framework)
	}

	pathname := normalizePath(request.Request.Path)
	method := strings.ToUpper(request.Request.Method)

	var selected *route
	var params map[string]string
	for index := range engine.routes {
		candidate := &engine.routes[index]
		if candidate.method != "ANY" && candidate.method != method {
			continue
		}

		matchedParams, ok := matchPath(candidate.path, pathname)
		if !ok {
			continue
		}

		selected = candidate
		params = matchedParams
		break
	}

	if selected == nil {
		return XGnosisCompatibilityResponse{Matched: false}, nil
	}

	rawBody, err := decodeBody(request.Request.Body)
	if err != nil {
		return XGnosisCompatibilityResponse{}, err
	}

	search := request.Request.Query
	if search != "" && !strings.HasPrefix(search, "?") {
		search = "?" + search
	}

	requestURL, err := url.Parse("http://xgnosis.invalid" + pathname + search)
	if err != nil {
		return XGnosisCompatibilityResponse{}, err
	}

	httpRequest := &http.Request{
		Method:        method,
		URL:           requestURL,
		Header:        http.Header{},
		Body:          ioNopCloser{Reader: bytes.NewReader(rawBody)},
		ContentLength: int64(len(rawBody)),
	}
	for key, value := range request.Request.Headers {
		httpRequest.Header.Set(key, value)
	}

	state := &responseState{
		status:  http.StatusOK,
		headers: http.Header{},
	}
	context := &Context{
		Request: httpRequest,
		Writer:  &ResponseWriter{state: state},
		params:  params,
		rawBody: rawBody,
		state:   state,
		index:   -1,
	}
	context.handlers = append(cloneHandlers(engine.middleware), selected.handlers...)
	context.Next()

	if state.status == 0 {
		state.status = http.StatusOK
	}

	return XGnosisCompatibilityResponse{
		Matched: true,
		Response: &XGnosisCompatibilityHttpResponse{
			Status:  state.status,
			Headers: flattenHeaders(state.headers),
			Body:    encodeBody(state.body),
		},
	}, nil
}

func XGnosisDispatchCompatibilityRequest(raw string) (XGnosisCompatibilityResponse, error) {
	if strings.TrimSpace(raw) == "" {
		return XGnosisCompatibilityResponse{}, fmt.Errorf("empty compatibility request")
	}

	var request XGnosisCompatibilityRequest
	if err := json.Unmarshal([]byte(raw), &request); err != nil {
		return XGnosisCompatibilityResponse{}, err
	}

	engine := LastEngine()
	if engine == nil {
		return XGnosisCompatibilityResponse{}, fmt.Errorf("no Gin engine was captured")
	}

	return engine.dispatch(request)
}

type ioNopCloser struct {
	Reader *bytes.Reader
}

func (closer ioNopCloser) Read(p []byte) (int, error) {
	return closer.Reader.Read(p)
}

func (closer ioNopCloser) Close() error {
	return nil
}
