func (mux *Mux) dispatch(request XGnosisCompatibilityRequest) (map[string]interface{}, error) {
	if strings.ToLower(request.Framework) != "chi" {
		return nil, fmt.Errorf("unsupported framework %q", request.Framework)
	}

	pathname := normalizeChiPath(request.Request.Path)
	method := strings.ToUpper(request.Request.Method)

	var selected *route
	var params map[string]string
	for index := range mux.routes {
		candidate := &mux.routes[index]
		if candidate.method != "ANY" && candidate.method != method {
			continue
		}
		matchedParams, ok := matchChiPath(candidate.path, pathname)
		if !ok {
			continue
		}
		selected = candidate
		params = matchedParams
		break
	}

	if selected == nil {
		return map[string]interface{}{
			"matched": false,
		}, nil
	}

	rawBody, err := decodeChiBody(request.Request.Body)
	if err != nil {
		return nil, err
	}

	search := request.Request.Query
	if search != "" && !strings.HasPrefix(search, "?") {
		search = "?" + search
	}

	requestURL, err := url.Parse("http://xgnosis.invalid" + pathname + search)
	if err != nil {
		return nil, err
	}

	httpRequest := &http.Request{
		Method:        method,
		URL:           requestURL,
		Header:        http.Header{},
		Body:          io.NopCloser(bytes.NewReader(rawBody)),
		ContentLength: int64(len(rawBody)),
	}
	for key, value := range request.Request.Headers {
		httpRequest.Header.Set(key, value)
	}
	httpRequest = httpRequest.WithContext(context.WithValue(httpRequest.Context(), routeParamsKey{}, params))

	recorder := &responseRecorder{
		header: http.Header{},
	}
	handler := selected.handler
	for index := len(selected.middlewares) - 1; index >= 0; index-- {
		handler = selected.middlewares[index](handler)
	}
	handler.ServeHTTP(recorder, httpRequest)

	if recorder.status == 0 {
		recorder.status = http.StatusOK
	}

	return map[string]interface{}{
		"matched": true,
		"response": map[string]interface{}{
			"status":  recorder.status,
			"headers": flattenChiHeaders(recorder.header),
			"body":    encodeChiBody(recorder.body),
		},
	}, nil
}

func XGnosisDispatchCompatibilityRequest(raw string) (map[string]interface{}, error) {
	if strings.TrimSpace(raw) == "" {
		return nil, fmt.Errorf("empty compatibility request")
	}

	var request XGnosisCompatibilityRequest
	if err := json.Unmarshal([]byte(raw), &request); err != nil {
		return nil, err
	}

	router := LastRouter()
	if router == nil {
		return nil, fmt.Errorf("no chi router was captured")
	}

	return router.dispatch(request)
}
