func normalizeEchoPath(path string) string {
	if path == "" {
		return "/"
	}
	if !strings.HasPrefix(path, "/") {
		path = "/" + path
	}
	if len(path) > 1 && strings.HasSuffix(path, "/") {
		path = strings.TrimSuffix(path, "/")
	}
	return path
}

func joinEchoPaths(prefix string, child string) string {
	normalizedPrefix := strings.TrimSuffix(normalizeEchoPath(prefix), "/")
	normalizedChild := normalizeEchoPath(child)
	if normalizedPrefix == "" || normalizedPrefix == "/" {
		return normalizedChild
	}
	if normalizedChild == "/" {
		return normalizedPrefix
	}
	return normalizedPrefix + normalizedChild
}

func splitEchoPath(path string) []string {
	trimmed := strings.Trim(normalizeEchoPath(path), "/")
	if trimmed == "" {
		return nil
	}
	return strings.Split(trimmed, "/")
}

func matchEchoPath(pattern string, actual string) (map[string]string, bool) {
	patternParts := splitEchoPath(pattern)
	actualParts := splitEchoPath(actual)
	params := map[string]string{}

	for index := 0; index < len(patternParts); index++ {
		if index >= len(actualParts) {
			return nil, false
		}

		part := patternParts[index]
		if strings.HasPrefix(part, ":") {
			params[strings.TrimPrefix(part, ":")] = actualParts[index]
			continue
		}
		if part != actualParts[index] {
			return nil, false
		}
	}

	if len(patternParts) != len(actualParts) {
		return nil, false
	}

	return params, true
}

